import{_ as e,o as l,c as d,a2 as o}from"./chunks/framework.VxKNwi4m.js";const x=JSON.parse('{"title":"대시보드 (Dashboard) 사용 매뉴얼","description":"","frontmatter":{},"headers":[],"relativePath":"intro/dashboard.md","filePath":"intro/dashboard.md","lastUpdated":1783915301000}'),a={name:"intro/dashboard.md"};function s(r,t,i,n,g,c){return l(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="대시보드-dashboard-사용-매뉴얼" tabindex="-1">대시보드 (Dashboard) 사용 매뉴얼 <a class="header-anchor" href="#대시보드-dashboard-사용-매뉴얼" aria-label="Permalink to &quot;대시보드 (Dashboard) 사용 매뉴얼&quot;">​</a></h1><p>대시보드는 프로젝트 정보, 계약 상황, 자금 흐름, 그리고 개인의 업무 현황까지 시스템 내의 다양한 비즈니스 지표를 한눈에 모니터링할 수 있는 사용자 개인 최적화 공간입니다.</p><h2 id="_1-주요-기능-및-조작-방법" tabindex="-1">1. 주요 기능 및 조작 방법 <a class="header-anchor" href="#_1-주요-기능-및-조작-방법" aria-label="Permalink to &quot;1. 주요 기능 및 조작 방법&quot;">​</a></h2><h3 id="💡-위젯-설정-및-개인화-customization" tabindex="-1">💡 위젯 설정 및 개인화 (Customization) <a class="header-anchor" href="#💡-위젯-설정-및-개인화-customization" aria-label="Permalink to &quot;💡 위젯 설정 및 개인화 (Customization)&quot;">​</a></h3><ul><li><strong>위젯 On/Off</strong>: 화면 우측 상단의 <strong>[위젯 설정]</strong> 버튼을 클릭하여 설정 패널을 엽니다. 노출을 원치 않거나 필요한 위젯의 스위치를 조절하여 화면에 배치할 수 있습니다.</li><li><strong>초기화</strong>: 배치 설정이 엉키거나 기본 화면으로 돌아가고 싶다면, 설정 패널 하단의 <strong>[기본값으로 초기화]</strong> 버튼을 클릭합니다.</li></ul><h3 id="🧩-레이아웃-조작-drag-resize" tabindex="-1">🧩 레이아웃 조작 (Drag &amp; Resize) <a class="header-anchor" href="#🧩-레이아웃-조작-drag-resize" aria-label="Permalink to &quot;🧩 레이아웃 조작 (Drag &amp; Resize)&quot;">​</a></h3><ul><li><strong>위치 이동 (Drag)</strong>: 위젯의 타이틀 영역이나 빈 곳을 마우스로 클릭한 채 원하는 위치로 드래그하면 바둑판 격자 위에서 위치가 재정렬됩니다.</li><li><strong>크기 조절 (Resize)</strong>: 위젯 우측 하단 모서리를 잡고 늘리거나 줄여 위젯 너비와 높이를 조정할 수 있습니다.</li><li><strong>상태 자동 저장</strong>: 사용자가 위치나 크기를 변경하는 즉시 자동으로 브라우저에 레이아웃 상태가 저장되므로, 페이지를 새로고침하거나 재방문해도 나만의 커스텀 배치가 그대로 유지됩니다.</li><li><strong>반응형 화면 대응</strong>: 해상도(데스크톱, 태블릿, 모바일 등)에 맞춰 격자 수가 동적으로 조절되므로 모바일 기기에서도 일관된 가독성을 보장합니다.</li></ul><h2 id="_2-제공-위젯-목록-widget-list" tabindex="-1">2. 제공 위젯 목록 (Widget List) <a class="header-anchor" href="#_2-제공-위젯-목록-widget-list" aria-label="Permalink to &quot;2. 제공 위젯 목록 (Widget List)&quot;">​</a></h2><p>대시보드에서 추가하여 사용할 수 있는 14가지 위젯들의 상세 기능입니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">위젯 이름 (Ko)</th><th style="text-align:left;">영어 식별자</th><th style="text-align:left;">설명 및 제공 데이터</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>메인 슬라이드</strong></td><td style="text-align:left;"><code>main-carousel</code></td><td style="text-align:left;">주요 배너 및 비주얼 이미지 슬라이드</td></tr><tr><td style="text-align:left;"><strong>오늘의 한마디</strong></td><td style="text-align:left;"><code>wise-word</code></td><td style="text-align:left;">사용자에게 보여지는 격언 및 동기부여 메시지</td></tr><tr><td style="text-align:left;"><strong>공지 목록</strong></td><td style="text-align:left;"><code>notice-list</code></td><td style="text-align:left;">회사 및 현장별 주요 공지사항 최근 목록</td></tr><tr><td style="text-align:left;"><strong>내 업무</strong></td><td style="text-align:left;"><code>my-issue</code></td><td style="text-align:left;">현재 로그인한 사용자 본인에게 할당된 진행 중인 작업 목록</td></tr><tr><td style="text-align:left;"><strong>회의록</strong></td><td style="text-align:left;"><code>meeting-minutes</code></td><td style="text-align:left;">최근 진행된 회의의 결정 사항 및 아젠다 요약</td></tr><tr><td style="text-align:left;"><strong>이슈 트래커</strong></td><td style="text-align:left;"><code>issue-tracker</code></td><td style="text-align:left;">등록된 전체 업무(이슈)의 유형별 상태 지표 모니터링</td></tr><tr><td style="text-align:left;"><strong>프로젝트 현황</strong></td><td style="text-align:left;"><code>project-status</code></td><td style="text-align:left;">각 현장 및 프로젝트의 기본 정보와 진행 상태 요약</td></tr><tr><td style="text-align:left;"><strong>현장별 분양 계약율</strong></td><td style="text-align:left;"><code>contract-status</code></td><td style="text-align:left;">각 현장 및 프로젝트의 계약 현황 요약 그래프</td></tr><tr><td style="text-align:left;"><strong>캘린더</strong></td><td style="text-align:left;"><code>calendar</code></td><td style="text-align:left;">프로젝트 주요 일정, 회의 정보 시각화</td></tr><tr><td style="text-align:left;"><strong>최근 등록 계약</strong></td><td style="text-align:left;"><code>contract-log</code></td><td style="text-align:left;">최근 이루어진 계약 및 수금 트랜잭션 기록</td></tr><tr><td style="text-align:left;"><strong>빠른 작업</strong></td><td style="text-align:left;"><code>quick-actions</code></td><td style="text-align:left;">주요 메뉴(업무 추가, 회의 등록 등)로 즉시 이동하는 단축 단추 모음</td></tr><tr><td style="text-align:left;"><strong>활동 피드</strong></td><td style="text-align:left;"><code>activity-feed</code></td><td style="text-align:left;">시스템 전반의 최근 업데이트 히스토리 타임라인</td></tr><tr><td style="text-align:left;"><strong>최근 문서 목록</strong></td><td style="text-align:left;"><code>document-list</code></td><td style="text-align:left;">최근 등록된 문서 공유 목록</td></tr><tr><td style="text-align:left;"><strong>현장별 수납 현황</strong></td><td style="text-align:left;"><code>financial-status</code></td><td style="text-align:left;">기초 회계 계정 기반 지출/수납 등의 재무 흐름 그래프 및 현황 제공</td></tr></tbody></table><h2 id="_3-️-권장-배치-가이드" tabindex="-1">3.️ 권장 배치 가이드 <a class="header-anchor" href="#_3-️-권장-배치-가이드" aria-label="Permalink to &quot;3.️ 권장 배치 가이드&quot;">​</a></h2><ul><li><strong>프로젝트 매니저 (PM) 추천</strong>: <ul><li>화면 상단: <code>프로젝트 현황</code>, <code>이슈 트래커</code></li><li>화면 중앙: <code>캘린더</code>, <code>회의록</code>, <code>활동 피드</code></li></ul></li><li><strong>재무 담당자 추천</strong>: <ul><li>화면 상단: <code>현장별 수납 현황</code>, <code>현장별 분양 계약율</code></li><li>화면 중앙: <code>최근 등록 계약</code>, <code>최근 문서 목록</code></li></ul></li><li><strong>일반 실무자 추천</strong>: <ul><li>화면 상단: <code>내 업무</code>, <code>빠른 작업</code></li><li>화면 중앙: <code>캘린더</code>, <code>공지 목록</code>, <code>오늘의 한마디</code></li></ul></li></ul>',12)])])}const h=e(a,[["render",s]]);export{x as __pageData,h as default};
